// Goal of the synthetic determinism postcondition:
//     (r1@ == self_@ && r2@ == self_@) ==> det_clone_up_to_view_equal(r1, r2)
// where
//     spec fn det_clone_up_to_view_equal(r1: EndPoint, r2: EndPoint) -> bool
//         { r1.id == r2.id }
//
// `EndPoint` and `AbstractEndPoint` are
//     pub struct EndPoint         { pub id: Vec<u8> }
//     pub struct AbstractEndPoint { pub id: Seq<u8> }
// with the open spec view
//     view(self) = AbstractEndPoint { id: self.id@ }.
//
// z3 returns `unknown` at the file level because the two per-run
// ensures `r1@ == self_@` and `r2@ == self_@` each fire view-unfolding
// on a disjoint trigger (the result-binder for that run), so the
// chain `r1@ == self_@ == r2@` is never materialised, and from there
// the `id` projection and Vec-level equality on `id` are never
// derived. The asserts below pull the chain into the proof context
// in explicit implication form so every step is something Verus has
// to verify — none of it is taken on faith.

// (1) Transitivity at the AbstractEndPoint view.
assert((r1@ == self_@ && r2@ == self_@) ==> r1@ == r2@);

// (2) AbstractEndPoint is a single-field struct, so view equality
//     projects to Seq<u8> equality on `.id@`.
assert((r1@ == self_@ && r2@ == self_@) ==> r1.id@ == self_.id@);
assert((r1@ == self_@ && r2@ == self_@) ==> r2.id@ == self_.id@);
assert((r1@ == self_@ && r2@ == self_@) ==> r1.id@ == r2.id@);

// (3) Pin Seq extensionality (`=~=`) so the per-index byte-equality
//     axioms fire on the same `r_i.id@.len()` / `r_i.id@[k]` triggers
//     that the schema-assume scaffolding below uses.
assert((r1@ == self_@ && r2@ == self_@) ==> r1.id@ =~= r2.id@);
assert((r1@ == self_@ && r2@ == self_@) ==> r1.id@.len() == r2.id@.len());

// (4) Reconstruct the AbstractEndPoint equality from the Seq facts,
//     ready to be chained back into the `r1@ == r2@` view-equality
//     z3 needs at the determinism-equal predicate's reduction site.
assert((r1@ == self_@ && r2@ == self_@) ==>
    AbstractEndPoint { id: r1.id@ } == AbstractEndPoint { id: r2.id@ });

// (5) Vec view-equality lifts to Vec spec equality on `id`, which is
//     exactly the body of `det_clone_up_to_view_equal(r1, r2)`.
assert((r1@ == self_@ && r2@ == self_@) ==> r1.id == r2.id);
